// Runnable — no return value, no checked exception
Runnable task = () -> {
    System.out.println("Processing in thread: " +
        Thread.currentThread().getName());
    // Cannot throw checked exception
};

// Callable — returns value, can throw checked exception
Callable<Integer> computation = () -> {
    Thread.sleep(1000); // checked exception — OK in Callable
    return 42;
};

ExecutorService pool = Executors.newFixedThreadPool(4);

// Submit Runnable
Future<?> rFuture = pool.submit(task);
rFuture.get(); // Always null

// Submit Callable
Future<Integer> cFuture = pool.submit(computation);
try {
    Integer result = cFuture.get(5, TimeUnit.SECONDS);
    System.out.println("Result: " + result); // 42
} catch (ExecutionException ex) {
    // Wraps exception thrown by call()
    log.error("Task failed", ex.getCause());
} catch (TimeoutException ex) {
    cFuture.cancel(true);
}

