// ABA problem
AtomicReference<String> ref = new AtomicReference<>("A");
// Thread 1 reads "A" ...
// Thread 2: A -> B -> A
ref.set("B"); ref.set("A");
// Thread 1 CAS("A", "C") — SUCCEEDS! But value changed and came back

// Fix: AtomicStampedReference
AtomicStampedReference<String> stamped =
    new AtomicStampedReference<>("A", 0);
int[] stampHolder = new int[1];
String current = stamped.get(stampHolder); // current="A", stamp=0
// Even if value returns to "A", stamp will be different
stamped.compareAndSet("A", "C", stampHolder[0], stampHolder[0] + 1);
// Only succeeds if BOTH value and stamp match

