// Sealed class hierarchy
public sealed interface Shape
    permits Circle, Rectangle, Triangle {}

public record Circle(double radius) implements Shape {}
public record Rectangle(double width, double height) implements Shape {}
public record Triangle(double base, double height) implements Shape {}

// Pattern matching switch — exhaustive (no default needed)
public double area(Shape shape) {
    return switch (shape) {
        case Circle c    -> Math.PI * c.radius() * c.radius();
        case Rectangle r -> r.width() * r.height();
        case Triangle t  -> 0.5 * t.base() * t.height();
        // Compiler ENFORCES exhaustiveness — add new Shape subtype
        // and this becomes a compile error until you add the case
    };
}

// Guarded patterns with 'when'
public String classify(Shape shape) {
    return switch (shape) {
        case Circle c when c.radius() > 100 -> "Large circle";
        case Circle c                        -> "Small circle";
        case Rectangle r when r.width() == r.height() -> "Square";
        case Rectangle r                    -> "Rectangle";
        case Triangle t                     -> "Triangle";
    };
}

