# Config Server application.yml
server.port: 8888
spring:
  cloud:
    config:
      server:
        git:
          uri: https://github.com/myorg/config-repo
          default-label: main
          search-paths: '{application}'
          clone-on-start: true
          # For private repos:
          username: ${GIT_USERNAME}
          password: ${GIT_TOKEN}
        encrypt:
          enabled: true

# config-repo/order-service.yml
order:
  processing-timeout: 30
  max-retries: 3

# config-repo/order-service-prod.yml
spring:
  datasource:
    url: ${DB_URL}
    password: '{cipher}AQB5mFl+...encrypted...value'

// Config Client
# bootstrap.yml (loaded before application.yml)
spring:
  application:
    name: order-service
  profiles:
    active: prod
  cloud:
    config:
      uri: http://config-server:8888
      fail-fast: true
      retry:
        max-attempts: 6
        initial-interval: 1000

// Fetch config programmatically
@RestController
public class ConfigController {
    @Value("${order.processing-timeout}")
    private int timeout;

    @GetMapping("/config")
    public Map<String, Object> getConfig() {
        return Map.of("timeout", timeout);
    }
}
